import java.util.*;class Player{static int W,H;static boolean[][]grid,vis;static double[]SL=new double[5];static double LS;public static void main(String[]args){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();grid=new boolean[H][W];vis=new boolean[H][W];int pi=0;while(s.hasNext()){String c=s.next();int l=s.nextInt();boolean b=c.equals("B");for(int j=0;j<l;j++){int y=pi/W,x=pi%W;if(y<H)grid[y][x]=b;pi++;}}int[]bc=new int[H];for(int y=0;y<H;y++)for(int x=0;x<W;x++)if(grid[y][x])bc[y]++;var groups=new ArrayList<List<Integer>>();var g=new ArrayList<Integer>();for(int y=0;y<H;y++){if(bc[y]>W*0.8){if(g.isEmpty()||y==g.get(g.size()-1)+1)g.add(y);else{groups.add(g);g=new ArrayList<>();g.add(y);}}else if(!g.isEmpty()){groups.add(g);g=new ArrayList<>();}}if(!g.isEmpty())groups.add(g);int bi=0;double bd=1e9;for(int i=0;i+4<groups.size();i++){double[]cs=new double[5];for(int j=0;j<5;j++){double sum=0;for(int v:groups.get(i+j))sum+=v;cs[j]=sum/groups.get(i+j).size();}double avg=0;double[]sp=new double[4];for(int j=0;j<4;j++){sp[j]=cs[j+1]-cs[j];avg+=sp[j];}avg/=4;double d=0;for(int j=0;j<4;j++)d+=Math.abs(sp[j]-avg);if(d<bd){bd=d;bi=i;}}for(int j=0;j<5;j++){double sum=0;for(int v:groups.get(bi+j))sum+=v;SL[j]=sum/groups.get(bi+j).size();}LS=(SL[4]-SL[0])/4;var notes=new ArrayList<int[]>();String nm="AGFEDCBAGFEDC";for(int x=0;x<W;x++)for(int y=0;y<H;y++){if(grid[y][x]&&!vis[y][x]){var q=new ArrayDeque<int[]>();q.add(new int[]{y,x});var px=new ArrayList<int[]>();int mx=W,MX=-1,my=H,MY=-1;while(!q.isEmpty()){var p=q.poll();int cy=p[0],cx=p[1];if(cy<0||cy>=H||cx<0||cx>=W||vis[cy][cx]||!grid[cy][cx])continue;vis[cy][cx]=true;px.add(p);mx=Math.min(mx,cx);MX=Math.max(MX,cx);my=Math.min(my,cy);MY=Math.max(MY,cy);for(int dy=-1;dy<=1;dy++)for(int dx=-1;dx<=1;dx++)if(dy!=0||dx!=0)q.add(new int[]{cy+dy,cx+dx});}if(px.size()<15)continue;var yw=new HashMap<Integer,int[]>();for(var p2:px){int py=p2[0],px2=p2[1];if(!yw.containsKey(py))yw.put(py,new int[]{px2,px2});else{yw.get(py)[0]=Math.min(yw.get(py)[0],px2);yw.get(py)[1]=Math.max(yw.get(py)[1],px2);}}int yc=-1,mw=-1;for(var e:yw.entrySet()){int w=e.getValue()[1]-e.getValue()[0]+1;if(w>mw){mw=w;yc=e.getKey();}}double ed=LS*0.6,eM=LS*1.5;if(mw<ed||mw>eM)continue;if(MY-my+1<ed||MX-mx+1>W*0.5)continue;int hr=(int)(LS/2),hmy=Math.max(0,yc-hr),hMy=Math.min(H-1,yc+hr);int bp=0;for(var p2:px)if(p2[0]>=hmy&&p2[0]<=hMy&&p2[1]>=mx&&p2[1]<=MX)bp++;int tp=(MX-mx+1)*(hMy-hmy+1);double fr=tp>0?(double)bp/tp:1;char nt=fr>0.5?'Q':'H';double hs=LS/2;int cl=0;double md2=1e9;for(int i=0;i<13;i++){double ny=SL[4]-hs*2+hs*i;double d=Math.abs(yc-ny);if(d<md2){md2=d;cl=i;}}notes.add(new int[]{mx,cl,nt});}}notes.sort((a,b)->a[0]-b[0]);var sb=new StringBuilder();for(int i=0;i<notes.size();i++){if(i>0)sb.append(' ');sb.append(nm.charAt(notes.get(i)[1]));sb.append((char)notes.get(i)[2]);}System.out.println(sb);}}